export default function PhoneBottomPopup({
  popupImage = '/api/images/7ff9e09eafad-popup-image.png',
  mainButtonText = '去看看',
  secondaryButtonText = '下次再说',
}: DemoProps) {
  return (
    <div
      className="relative w-full overflow-hidden bg-white"
      style={{
        height: '100vh',
        maxWidth: 375,
        margin: '0 auto',
