              </div>
              <span
                className="text-[#666] text-center text-lg font-normal leading-[150%] cursor-pointer"
                style={{ fontFamily: '"PingFang SC", sans-serif' }}
              >
                {secondaryButtonText}
              </span>
            </div>
          </div>
        </div>
      </div>
